//! v1 Ergopad staking contract constants.

/// v1 StakeBox P2S address (full). Used with `unspent_boxes_by_address` which
/// is reliably indexed on `extraIndex` nodes, unlike `byErgoTree` which some
/// node configs fail to return results for even when the address index is healthy.
pub const STAKE_BOX_ADDRESS: &str = "";

/// v1 StakeStateBox P2S address (full).
pub const STAKE_STATE_ADDRESS: &str = "";

/// ErgoTree of the v1 StakeBox (P2S `3eiC8caSy3ji…dFR9`).
/// Each StakeBox holds 1 stake token + N ERGOPAD, with R4 = [checkpoint, stakeTimeMs]
/// and R5 = stake key NFT ID (Coll[Byte]).
pub const STAKE_BOX_ERGO_TREE: &str = "";

/// ErgoTree of the v1 StakeStateBox (P2S `HuZk…U3Gu`).
/// R4 = [totalStakedRaw, checkpoint, numStakers, lastCheckpointTs, cycleDurationMs].
pub const STAKE_STATE_ERGO_TREE: &str = "";

/// Singleton NFT identifying the unique v1 StakeStateBox.
pub const STAKE_STATE_NFT: &str =
    "05cde13424a7972fbcd0b43fccbb5e501b1f75302175178fc86d8f243f3f3125";

/// Pool-wide stake token. One unit per active StakeBox; remainder sits in the StakeStateBox.
pub const STAKE_TOKEN: &str =
    "1028de73d018f0c9a374b71555c5b8f1390994f2f41633e7b9d68f77735782ee";

/// The ERGOPAD token.
pub const ERGOPAD_TOKEN: &str =
    "d71693c49a84fbbecd4908c94813b46514b18b67a99952dc1e6e4791556de413";

/// ERGOPAD has 2 decimals.
pub const ERGOPAD_DECIMALS: u32 = 2;

pub const MIN_MINER_FEE: u64 = citadel_core::constants::TX_FEE_NANO as u64;
pub const MIN_BOX_VALUE: u64 = citadel_core::constants::MIN_BOX_VALUE_NANO as u64;
pub const MIN_CHANGE_VALUE: u64 = 1_000_000;

/// Pagination for `unspent_boxes_by_ergo_tree` when scanning the stake P2S.
pub const STAKE_BOX_PAGE_SIZE: u64 = 500;
/// Upper bound on pages to scan (500 × 20 = 10,000 boxes).
pub const STAKE_BOX_MAX_PAGES: u64 = 20;
